const q = ($input.first().json.query) || {};
const pid = (q.project_id || '').trim();
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(pid)) {
  return [{ json: { valid:false, html: '<!DOCTYPE html><html><body style="font-family:Arial;max-width:600px;margin:48px auto;padding:24px"><h1>Falta project_id</h1><p>Uso: <code>/webhook/admin-project?project_id=&lt;uuid&gt;</code></p></body></html>' } }];
}
return [{ json: { valid:true, project_id: pid } }];

const s = $input.first().json.snapshot || {};
const p = s.project || {};
const c = s.client || {};
const b = s.briefing || {};
const d = s.design || {};
const ce = s.cost_estimate || {};
const inv = s.invoices || [];
const permits = s.permits || [];
const aftercare = s.aftercare || [];
const paths = s.pathology || [];
const reg = s.regulatory || [];
const contracts = s.contracts || [];
const notes = s.notes || [];
const sevColor = { critical: '#7f1d1d', high: '#dc2626', medium: '#ea580c', low: '#10b981' };
const card = (label, value, unit) => '<div style="background:#f9fafb;padding:12px;border-radius:6px;flex:1;min-width:130px"><div style="font-size:10px;color:#6b7280;text-transform:uppercase">'+label+'</div><div style="font-size:20px;font-weight:bold;color:#1f2937;margin-top:4px">'+(value!=null?value:'-')+(unit?'<span style="font-size:11px;color:#6b7280"> '+unit+'</span>':'')+'</div></div>';
const row = (cells) => '<tr>'+cells.map(c=>'<td style="padding:6px 8px;border-bottom:1px solid #eee;font-size:12px">'+c+'</td>').join('')+'</tr>';
const section = (title, body) => '<h2 style="color:#374151;font-size:15px;margin:20px 0 8px">'+title+'</h2>'+body;
const sevBadge = sev => '<span style="background:'+(sevColor[sev]||'#6b7280')+';color:white;padding:1px 6px;border-radius:3px;font-size:10px">'+(sev||'?').toUpperCase()+'</span>';
const tbl = (headers, rows) => '<table style="width:100%;background:white;border-collapse:collapse"><thead style="background:#1f2937;color:white"><tr>'+headers.map(h=>'<th style="padding:8px;text-align:left;font-size:11px">'+h+'</th>').join('')+'</tr></thead><tbody>'+(rows.length>0?rows.join(''):row(headers.map(()=>'<i style="color:#6b7280">vacio</i>')))+'</tbody></table>';
if (!p.id) {
  const html = '<!DOCTYPE html><html><body style="font-family:Arial;max-width:600px;margin:48px auto;padding:24px"><h1>Proyecto no encontrado</h1></body></html>';
  return [{ json: { html } }];
}
const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>'+(p.name||'?')+' — admin view</title>' +
'<style>body{font-family:-apple-system,Arial,sans-serif;max-width:1100px;margin:24px auto;padding:16px;color:#1f2937;background:#f3f4f6}h1{color:#0f172a;margin:0 0 4px}.cards{display:flex;gap:10px;flex-wrap:wrap;margin:12px 0}.meta{color:#64748b;font-size:13px}</style>' +
'</head><body>' +
'<a href="/webhook/admin-index" style="color:#2563eb;font-size:13px;text-decoration:none">← Admin index</a>' +
'<h1>'+(p.name||'(sin nombre)')+'</h1>' +
'<div class="meta">' + (p.project_type||'?')+' • ' + (p.property_type||'?') + ' ' + (p.property_area_m2||'?') + 'm² • ' + (p.location_city||'?') + ' • fase: <code>'+(p.current_phase||'?')+'</code> • cliente: <b>'+(c.name||'?')+'</b></div>' +
'<div class="cards" style="margin-top:16px">' +
  card('Budget', Number(p.budget_target||0).toLocaleString('es-ES'), 'EUR') +
  card('Estimado', Number(ce.total_estimated||0).toLocaleString('es-ES'), 'EUR') +
  card('Facturado', Number(s.invoices_total||0).toLocaleString('es-ES'), 'EUR') +
  card('LLM cost', s.llm_cost_total||0, 'USD') +
  card('Calls', s.llm_calls_total||0) +
  card('Failed', s.agent_executions_failed||0) +
  card('Tokens', s.tokens_active||0) +
  card('Consultas', s.consultations_pending||0) +
'</div>' +

section('Notas del arquitecto ('+notes.length+')', notes.length>0 ? '<ul style="background:white;padding:14px;border-radius:6px;list-style:none;margin:0">' + notes.slice(0,15).map(n => '<li style="padding:8px;border-bottom:1px solid #eee"><span style="background:'+(n.pinned?'#fbbf24':'#e5e7eb')+';color:'+(n.pinned?'#78350f':'#374151')+';padding:1px 8px;border-radius:3px;font-size:10px;text-transform:uppercase;margin-right:6px">'+(n.pinned?'PIN':'')+(n.category||'general').slice(0,12)+'</span>'+(n.body||'')+'<div style="font-size:11px;color:#9ca3af;margin-top:4px">'+new Date(n.created_at).toISOString().slice(0,10)+'</div></li>').join('') + '</ul>' : '<i style="color:#6b7280">sin notas. Crear via POST /webhook/admin-note</i>') +

section('Cliente', '<div style="background:white;padding:12px;border-radius:6px;font-size:13px">Nombre: <b>'+(c.name||'?')+'</b><br>Email: <code>'+(c.email||'-')+'</code><br>Telefono: '+(c.phone||'-')+'</div>') +

section('Briefing', b.summary ? '<div style="background:white;padding:12px;border-radius:6px"><p>'+(b.summary||'')+'</p><div style="font-size:12px;color:#6b7280;margin-top:8px">version '+(b.version||1)+' • '+(b.status||'?')+'</div></div>' : '<i style="color:#6b7280">sin briefing aprobado</i>') +

section('Diseno seleccionado', d.title ? '<div style="background:white;padding:12px;border-radius:6px"><b>Opcion '+(d.option_number||'?')+':</b> '+d.title+'<br><div style="color:#374151;font-size:13px;margin-top:6px">'+(d.description||'').substring(0,300)+'</div></div>' : '<i style="color:#6b7280">no seleccionado</i>') +

section('Tramites administrativos ('+reg.length+')',
  tbl(['Tipo','Titulo','Status','Prioridad'], reg.map(r => row([r.task_type||'-', (r.title||'').slice(0,60), '<code>'+(r.status||'-')+'</code>', sevBadge(r.priority)])))
) +

section('Permits ('+permits.length+')',
  tbl(['Tipo','Entidad','Status','Expediente'], permits.map(pe => row([pe.application_type||'-', pe.entity||'-', '<code>'+(pe.status||'-')+'</code>', pe.expediente_id||'-'])))
) +

section('Patologias ('+paths.length+')',
  tbl(['Tipo','Severidad','Status'], paths.map(pa => row([pa.pathology_type||'-', sevBadge(pa.severity), '<code>'+(pa.status||'-')+'</code>'])))
) +

section('Aftercare/postventa ('+aftercare.length+')',
  tbl(['Cuando','Severidad','Categoria','Status','Preview'], aftercare.slice(0,10).map(a => row([(a.reported_at||'').slice(0,10), sevBadge(a.severity), a.category||'-', '<code>'+(a.status||'-')+'</code>', a.preview||'-'])))
) +

section('Contratos ('+contracts.length+')',
  tbl(['Tipo','Status','Firmado','Expira'], contracts.map(c => row([c.contract_type||'-', '<code>'+(c.status||'-')+'</code>', (c.signed_at||'').slice(0,10), (c.expires_at||'').slice(0,10)])))
) +

section('Facturas ('+inv.length+')',
  tbl(['Proveedor','Fecha','Total','Status'], inv.slice(0,15).map(i => row([i.supplier_name||'-', (i.invoice_date||'').slice(0,10), Number(i.total_amount||0).toLocaleString('es-ES')+' EUR', '<code>'+(i.status||'-')+'</code>'])))
) +

'<p style="color:#94a3b8;font-size:11px;margin-top:32px;text-align:center">project_id: <code>'+p.id+'</code></p>' +
'</body></html>';
return [{ json: { html } }];
